## Recommended Improvements

Here's what an improved version would look like:

```js
const express = require('express');
const helmet = require('helmet');           // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();

// --- Security Middleware ---
app.use(helmet());                          // Sets secure HTTP headers

// Parse JSON with a size limit to prevent memory exhaustion
app.use(express.json({ limit: '10kb' }));

// Rate limiting: max 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by');               // helmet does this too, but explicit is good

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate query parameters if accepting any (e.g., pagination)
  const page = parseInt(req.query.page, 10);
  const limit = parseInt(req.query.limit, 10);

  if (req.query.page !== undefined && (isNaN(page) || page < 1)) {
    return res.status(400).json({ error: 'Invalid page parameter' });
  }
  if (req.query.limit !== undefined && (isNaN(limit) || limit < 1 || limit > 100)) {
    return res.status(400).json({ error: 'Invalid limit parameter (1-100)' });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json(users);
});

// --- 404 handler for undefined routes ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (MUST have 4 params) ---
app.use((err, req, res, next) => {
  // Log the full error internally but never expose it to clients
  console.error('Unhandled error:', err.message);

  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Start server ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

