const express = require('express');
const helmet = require('helmet');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Set security-related HTTP headers (XSS protection, content-type sniffing, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload attacks
app.use(express.json({ limit: '10kb' }));

// Disable the X-Powered-By header to avoid revealing tech stack
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const { limit, offset } = req.query;

  if (limit !== undefined && (isNaN(Number(limit)) || Number(limit) < 0)) {
    return res.status(400).json({ error: 'Invalid "limit" parameter. Must be a non-negative number.' });
  }
  if (offset !== undefined && (isNaN(Number(offset)) || Number(offset) < 0)) {
    return res.status(400).json({ error: 'Invalid "offset" parameter. Must be a non-negative number.' });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  const parsedLimit = limit ? Math.min(Number(limit), 100) : 100; // Cap max results
  const parsedOffset = offset ? Number(offset) : 0;
  const paginatedUsers = users.slice(parsedOffset, parsedOffset + parsedLimit);

  res.json({ data: paginatedUsers, total: users.length });
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global Error Handler ---
// Must have 4 parameters so Express recognizes it as an error handler
app.use((err, _req, res, _next) => {
  // Log the full error internally for debugging
  console.error('Unhandled error:', err);

  // Never expose internal error details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal Server Error'
      : err.message,
  });
});

// --- Server Start ---
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

